#include <stdio.h>
int bsearch(int arr[], int n, int target) {
    int left=0, right=n-1, mid;
    while(left<=right) {
        mid = (left+right)/2;
        if(arr[mid]==target) return mid;
        else if(arr[mid]<target) left=mid+1;
        else right=mid-1;
    }
    return -1;
}
int main() {
    int a[] = {1,3,5,7,9,11};
    printf("%d", bsearch(a, 6, 7));
    return 0;
}

